import React from "react";
import { useNavigate, useLocation } from "react-router-dom";

const InteractionMode = () => {
    const navigate = useNavigate();
    const location = useLocation();

    // Retrieve the selected avatar passed via state
    const { avatar } = location.state || { avatar: null };

    return (
        <div style={{ textAlign: "center", padding: "50px" }}>
            <h1>Choose your mode of interaction</h1>
            <div style={{ display: "flex", justifyContent: "center", gap: "30px", marginTop: "30px" }}>
                {/* Online Mode */}
                <div
                    onClick={() => navigate("/online")}
                    style={{
                        cursor: "pointer",
                        textAlign: "center",
                        border: "1px solid #ccc",
                        borderRadius: "10px",
                        padding: "20px",
                        width: "200px",
                    }}
                >
                    <video
                        src="/videos/online-mode.mp4"
                        autoPlay
                        loop
                        muted
                        style={{
                            width: "100%",
                            height: "150px",
                            objectFit: "cover",
                            borderRadius: "8px",
                        }}
                    />
                    <p style={{ marginTop: "10px" }}>Online Mode</p>
                </div>

                {/* Offline Mode */}
                <div
                    onClick={() => navigate("/offline")}
                    style={{
                        cursor: "pointer",
                        textAlign: "center",
                        border: "1px solid #ccc",
                        borderRadius: "10px",
                        padding: "20px",
                        width: "200px",
                    }}
                >
                    {avatar ? (
                        <img
                            src={avatar.image}
                            alt={avatar.name}
                            style={{
                                width: "100%",
                                height: "150px",
                                objectFit: "cover",
                                borderRadius: "8px",
                            }}
                        />
                    ) : (
                        <p>No avatar selected</p>
                    )}
                    <p style={{ marginTop: "10px" }}>Offline Mode</p>
                </div>
            </div>
        </div>
    );
};

export default InteractionMode;
